import React, { useState } from 'react';
import './App.css';

const COLORS = {
  Cardiology:       '#ef4444',
  Neurology:        '#a78bfa',
  Orthopedics:      '#38bdf8',
  Gastroenterology: '#22c55e',
  Other:            '#94a3b8'
};

const ICONS = {
  Cardiology:       '❤️',
  Neurology:        '🧠',
  Orthopedics:      '🦴',
  Gastroenterology: '🫁',
  Other:            '🏥'
};

const SAMPLES = [
  {
    label: 'Cardiology',
    text: 'Patient presents with chest pain radiating to left arm, ST elevation on EKG, troponin elevated at 2.4. History of hypertension. Started on aspirin, nitroglycerin, heparin drip. Impression: Acute inferior STEMI.'
  },
  {
    label: 'Neurology',
    text: 'Patient with sudden onset severe headache, worst of life, neck stiffness, photophobia. CT negative for hemorrhage. LP shows cloudy fluid, WBC 1200 neutrophil predominant. Started ceftriaxone. Diagnosis: Bacterial meningitis.'
  },
  {
    label: 'Orthopedics',
    text: 'Patient presents with right knee pain after sports injury. MRI shows complete ACL tear with bone bruising. Discussed surgical options including ACL reconstruction with patellar tendon autograft.'
  },
  {
    label: 'Gastroenterology',
    text: 'Colonoscopy performed for screening. Three polyps found in sigmoid colon, removed via polypectomy. Pathology shows tubular adenoma. Recommend follow up colonoscopy in 3 years.'
  },
  {
    label: 'Other',
    text: 'Fiebre alta y dolor de garganta en paciente de 8 años. Se observa eritema faríngeo con exudado. Prueba rápida de estreptococo positiva. Se prescribe amoxicilina 500mg.'
  }
];

export default function App() {
  const [note,    setNote]    = useState('');
  const [result,  setResult]  = useState(null);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState('');

  const handleAnalyze = async () => {
    if (!note.trim()) return;
    setLoading(true);
    setResult(null);
    setError('');
    try {
      const res = await fetch('http://127.0.0.1:5000/predict', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ note })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setResult(data);
    } catch (err) {
      setError('Could not connect to model. Make sure Flask is running on port 5000.');
    } finally {
      setLoading(false);
    }
  };

  const handleSample = (text) => {
    setNote(text);
    setResult(null);
    setError('');
  };

  const highlightKeywords = (text, keywords) => {
    if (!keywords || keywords.length === 0) return text;
    const regex = new RegExp(`\\b(${keywords.join('|')})\\b`, 'gi');
    const parts = text.split(regex);
    return parts.map((part, i) =>
      keywords.some(k => k.toLowerCase() === part.toLowerCase())
        ? <mark key={i} className="highlight">{part}</mark>
        : part
    );
  };

  const color = result ? COLORS[result.prediction] : null;

  return (
    <div className="app">
      <header className="header">
        <div className="header-left">
          <div className="logo">⚕ ClinicalAI <span>Classifier</span></div>
          <div className="header-sub">Medical specialty classification · CodaMetrix Hackathon 2026</div>
        </div>
        <div className="header-badge">Team Demo</div>
      </header>

      <main className="main">
        {/* Left panel - input */}
        <div className="left-panel">
          <div className="panel">
            <div className="panel-header">
              <h2>Clinical Note</h2>
              <div className="sample-row">
                <span className="sample-label">Samples:</span>
                {SAMPLES.map((s, i) => (
                  <button
                    key={i}
                    className="btn-sample"
                    style={{ borderColor: COLORS[s.label] }}
                    onClick={() => handleSample(s.text)}
                  >
                    {ICONS[s.label]} {s.label}
                  </button>
                ))}
              </div>
            </div>

            {result ? (
              <div className="note-display">
                {highlightKeywords(note, result.keywords)}
              </div>
            ) : (
              <textarea
                className="note-input"
                placeholder="Paste a clinical note here..."
                value={note}
                onChange={e => { setNote(e.target.value); setResult(null); }}
              />
            )}

            <div className="input-footer">
              <span className="char-count">{note.length} chars</span>
              <div style={{ display: 'flex', gap: '0.5rem' }}>
                {result && (
                  <button className="btn-secondary" onClick={() => { setResult(null); }}>
                    Edit Note
                  </button>
                )}
                <button
                  className="btn-primary"
                  onClick={handleAnalyze}
                  disabled={!note.trim() || loading}
                >
                  {loading ? '⏳ Analyzing...' : '🔍 Classify'}
                </button>
              </div>
            </div>
          </div>

          {error && <div className="alert-error">{error}</div>}
        </div>

        {/* Right panel - results */}
        <div className="right-panel">
          {!result && !loading && (
            <div className="empty-state">
              <div className="empty-icon">⚕</div>
              <div className="empty-title">Paste a clinical note and click Classify</div>
              <div className="empty-sub">The model will predict the medical specialty and show which keywords drove the decision.</div>
            </div>
          )}

          {loading && (
            <div className="empty-state">
              <div className="spinner" />
              <div className="empty-title">Analyzing note...</div>
            </div>
          )}

          {result && (
            <>
              {/* Main prediction */}
              <div className="prediction-card" style={{ borderColor: color }}>
                <div className="prediction-label">Predicted Specialty</div>
                <div className="prediction-value" style={{ color }}>
                  {ICONS[result.prediction]} {result.prediction}
                </div>
                <div className="prediction-confidence" style={{ color }}>
                  {result.confidence}% confidence
                </div>
              </div>

              {/* Probability bars */}
              <div className="panel">
                <div className="panel-header"><h2>All Probabilities</h2></div>
                <div className="prob-list">
                  {Object.entries(result.probabilities)
                    .sort((a, b) => b[1] - a[1])
                    .map(([specialty, pct]) => (
                      <div key={specialty} className="prob-row">
                        <div className="prob-label">
                          {ICONS[specialty]} {specialty}
                        </div>
                        <div className="prob-bar-wrap">
                          <div
                            className="prob-bar"
                            style={{
                              width: `${pct}%`,
                              background: COLORS[specialty]
                            }}
                          />
                        </div>
                        <div className="prob-pct">{pct}%</div>
                      </div>
                    ))}
                </div>
              </div>

              {/* Keywords */}
              {result.keywords && result.keywords.length > 0 && (
                <div className="panel">
                  <div className="panel-header"><h2>Key Terms That Drove This Decision</h2></div>
                  <div className="keywords-wrap">
                    {result.keywords.map((kw, i) => (
                      <span key={i} className="keyword-pill" style={{ borderColor: color, color }}>
                        {kw}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </>
          )}
        </div>
      </main>

      <footer className="footer">
        Built for CodaMetrix Calling Hackathon · June 2026 · Edwin Sorto Rosales & Team
      </footer>
    </div>
  );
}
